import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Shield, Eye, EyeOff, ArrowLeft, AlertCircle, CheckCircle } from "lucide-react";
import { toast } from "react-toastify";
import { authAPI } from "../utils/api";

const RANKS = ["Constable", "Head Constable", "Sub-Inspector", "Inspector", "Deputy Superintendent", "Superintendent", "Deputy Inspector General", "Inspector General", "Director General"];

export default function RegisterPage() {
  const [form, setForm] = useState({ name: "", badgeId: "", email: "", password: "", confirmPassword: "", rank: "", station: "" });
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [success, setSuccess] = useState(false);
  const navigate = useNavigate();

  const update = (field, val) => {
    setForm(f => ({ ...f, [field]: val }));
    if (errors[field]) setErrors(e => ({ ...e, [field]: "" }));
  };

  const validate = () => {
    const e = {};
    if (!form.name || form.name.trim().length < 3) e.name = "Full name is required (min 3 chars).";
    if (!form.badgeId || !/^[A-Z]{2,5}-\d{3,6}$/.test(form.badgeId)) e.badgeId = "Format: XX-000 (e.g. HYD-001)";
    if (!form.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) e.email = "Valid email is required.";
    if (!form.password || form.password.length < 8) e.password = "Password must be at least 8 characters.";
    if (form.password !== form.confirmPassword) e.confirmPassword = "Passwords do not match.";
    if (!form.rank) e.rank = "Select your rank.";
    if (!form.station || form.station.trim().length < 3) e.station = "Station name is required.";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    try {
      await authAPI.register({ name: form.name, badgeId: form.badgeId.toUpperCase(), email: form.email, password: form.password, rank: form.rank, station: form.station });
      setSuccess(true);
      toast.success("Account registered! You can now login.");
      setTimeout(() => navigate("/login"), 2000);
    } catch (err) {
      toast.error(err.response?.data?.message || "Registration failed.");
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div style={{ minHeight: "100vh", background: "var(--gradient-hero)", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <div className="card animate-fadeInUp" style={{ maxWidth: 380, width: "100%", padding: 40, textAlign: "center" }}>
          <div style={{ width: 64, height: 64, borderRadius: "50%", background: "var(--accent-green-dim)", border: "2px solid rgba(52,211,153,0.3)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px" }}>
            <CheckCircle size={32} color="var(--accent-green)" />
          </div>
          <h2 style={{ fontFamily: "var(--font-display)", fontSize: 22, marginBottom: 8 }}>Account Registered!</h2>
          <p style={{ color: "var(--text-secondary)", fontSize: 14 }}>Redirecting to login...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", background: "var(--gradient-hero)", display: "flex", alignItems: "center", justifyContent: "center", padding: "40px 24px 20px" }}>
      <div style={{ width: "100%", maxWidth: 480 }} className="animate-fadeInUp">
        <Link to="/" style={{ display: "inline-flex", alignItems: "center", gap: 4, color: "var(--text-muted)", fontSize: 11, textDecoration: "none", marginBottom: 12 }}>
          <ArrowLeft size={12} /> Back to home
        </Link>
        <div className="card" style={{ padding: "16px 24px" }}>
          <div style={{ textAlign: "center", marginBottom: 16 }}>
            <div style={{ width: 40, height: 40, borderRadius: 10, background: "rgba(56,189,248,0.1)", border: "1px solid rgba(56,189,248,0.2)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 8px" }}>
              <Shield size={20} color="var(--accent-cyan)" />
            </div>
            <h1 className="text-gradient" style={{ fontFamily: "var(--font-display)", fontSize: 18, fontWeight: 800, marginBottom: 4 }}>Official Registration</h1>
            <p style={{ color: "var(--text-secondary)", fontSize: 11, margin: 0 }}>Register your official credentials to access the crime reporting portal.</p>
          </div>

          <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
              <div className="form-group" style={{ gridColumn: "1 / -1", gap: 4 }}>
                <label className="form-label" style={{ fontSize: 10 }}>Full Name <span className="required">*</span></label>
                <input className="form-control" style={{ padding: "6px 10px", fontSize: 11 }} placeholder="Your full official name" value={form.name} onChange={e => update("name", e.target.value)} />
                {errors.name && <p className="form-error" style={{ fontSize: 9, margin: 0 }}>{errors.name}</p>}
              </div>

              <div className="form-group" style={{ gap: 4 }}>
                <label className="form-label" style={{ fontSize: 10 }}>Badge ID <span className="required">*</span></label>
                <input className="form-control" style={{ padding: "6px 10px", fontSize: 11 }} placeholder="HYD-001" value={form.badgeId} onChange={e => update("badgeId", e.target.value.toUpperCase())} />
                {errors.badgeId && <p className="form-error" style={{ fontSize: 9, margin: 0 }}>{errors.badgeId}</p>}
              </div>

              <div className="form-group" style={{ gap: 4 }}>
                <label className="form-label" style={{ fontSize: 10 }}>Rank <span className="required">*</span></label>
                <select className="form-control" style={{ padding: "6px 10px", fontSize: 11 }} value={form.rank} onChange={e => update("rank", e.target.value)}>
                  <option value="">Select rank...</option>
                  {RANKS.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
                {errors.rank && <p className="form-error" style={{ fontSize: 9, margin: 0 }}>{errors.rank}</p>}
              </div>

              <div className="form-group" style={{ gridColumn: "1 / -1", gap: 4 }}>
                <label className="form-label" style={{ fontSize: 10 }}>Official Email <span className="required">*</span></label>
                <input className="form-control" style={{ padding: "6px 10px", fontSize: 11 }} type="email" placeholder="you@police.gov.in" value={form.email} onChange={e => update("email", e.target.value)} />
                {errors.email && <p className="form-error" style={{ fontSize: 9, margin: 0 }}>{errors.email}</p>}
              </div>

              <div className="form-group" style={{ gridColumn: "1 / -1", gap: 4 }}>
                <label className="form-label" style={{ fontSize: 10 }}>Police Station <span className="required">*</span></label>
                <input className="form-control" style={{ padding: "6px 10px", fontSize: 11 }} placeholder="e.g. Banjara Hills Police Station" value={form.station} onChange={e => update("station", e.target.value)} />
                {errors.station && <p className="form-error" style={{ fontSize: 9, margin: 0 }}>{errors.station}</p>}
              </div>

              <div className="form-group" style={{ gap: 4 }}>
                <label className="form-label" style={{ fontSize: 10 }}>Password <span className="required">*</span></label>
                <div style={{ position: "relative" }}>
                  <input className="form-control" style={{ padding: "6px 24px 6px 10px", fontSize: 11 }} type={showPass ? "text" : "password"} placeholder="Min 8 characters" value={form.password} onChange={e => update("password", e.target.value)} />
                  <button type="button" onClick={() => setShowPass(s => !s)} style={{ position: "absolute", right: 8, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "var(--text-muted)" }}>
                    {showPass ? <EyeOff size={12} /> : <Eye size={12} />}
                  </button>
                </div>
                {errors.password && <p className="form-error" style={{ fontSize: 9, margin: 0 }}>{errors.password}</p>}
              </div>

              <div className="form-group" style={{ gap: 4 }}>
                <label className="form-label" style={{ fontSize: 10 }}>Confirm Password <span className="required">*</span></label>
                <input className="form-control" style={{ padding: "6px 10px", fontSize: 11 }} type="password" placeholder="Repeat password" value={form.confirmPassword} onChange={e => update("confirmPassword", e.target.value)} />
                {errors.confirmPassword && <p className="form-error" style={{ fontSize: 9, margin: 0 }}>{errors.confirmPassword}</p>}
              </div>
            </div>

            <div style={{ display: "flex", alignItems: "flex-start", gap: 6, padding: "6px 10px", background: "rgba(56,189,248,0.06)", border: "1px solid rgba(56,189,248,0.15)", borderRadius: 6, fontSize: 10, color: "var(--text-secondary)", lineHeight: 1.3 }}>
              <AlertCircle size={12} color="var(--accent-cyan)" style={{ flexShrink: 0, marginTop: 1 }} />
              False registration is a criminal offence. Credentials will be verified before dashboard access is granted.
            </div>

            <button type="submit" className="btn btn-primary" style={{ padding: "8px 16px", fontSize: 12, marginTop: 4 }} disabled={loading}>
              {loading ? <><span className="spinner" style={{ width: 14, height: 14 }} /> Registering...</> : <><Shield size={14} /> Register</>}
            </button>
          </form>

          <hr className="divider" style={{ margin: "16px 0" }} />
          <p style={{ textAlign: "center", fontSize: 11, color: "var(--text-muted)", margin: 0 }}>
            Already registered? <Link to="/login" style={{ color: "var(--accent-cyan)", textDecoration: "none", fontWeight: 500 }}>Login →</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
